def find_zach(obj, path=""):
    results = []
    if isinstance(obj, dict):
        for k,v in obj.items():
            if k == "zach" or (isinstance(v, dict) and v.get("burst")=="zach"):
                results.append((path+"/"+k, v))
            results.extend(find_zach(v, path+"/"+k))
    elif isinstance(obj, list):
        for i,v in enumerate(obj):
            results.extend(find_zach(v, path+f"[{i}]"))
    return results

